import os
import json
import hashlib
from typing import List, Dict, Optional
from dataclasses import dataclass, field
from pathlib import Path
import numpy as np
from openai import OpenAI


@dataclass
class Document:
    """Represents a document chunk with metadata."""
    content: str
    source: str
    chunk_id: str
    metadata: Dict = field(default_factory=dict)
    embedding: Optional[List[float]] = None


class VectorStore:
    """Simple in-memory vector store using cosine similarity."""

    def __init__(self):
        self.documents: List[Document] = []
        self.embeddings: Optional[np.ndarray] = None

    def add_documents(self, documents: List[Document]):
        """Add documents with their embeddings to the store."""
        self.documents.extend(documents)
        embeddings = [doc.embedding for doc in self.documents if doc.embedding is not None]
        if embeddings:
            self.embeddings = np.array(embeddings)

    def search(self, query_embedding: List[float], top_k: int = 5) -> List[tuple]:
        """Search for most similar documents using cosine similarity."""
        if self.embeddings is None or len(self.documents) == 0:
            return []

        query_vec = np.array(query_embedding)
        query_norm = np.linalg.norm(query_vec)
        if query_norm == 0:
            return []

        doc_norms = np.linalg.norm(self.embeddings, axis=1)
        valid_mask = doc_norms > 0
        similarities = np.zeros(len(self.documents))
        if np.any(valid_mask):
            similarities[valid_mask] = (
                np.dot(self.embeddings[valid_mask], query_vec)
                / (doc_norms[valid_mask] * query_norm)
            )

        top_indices = np.argsort(similarities)[::-1][:top_k]
        results = [(self.documents[i], float(similarities[i])) for i in top_indices]
        return results

    def get_stats(self) -> Dict:
        """Return statistics about the vector store."""
        return {
            "total_documents": len(self.documents),
            "sources": list(set(doc.source for doc in self.documents)),
            "has_embeddings": self.embeddings is not None,
        }

    def save(self, path: str):
        """Persist vector store to disk."""
        data = {
            "documents": [
                {
                    "content": doc.content,
                    "source": doc.source,
                    "chunk_id": doc.chunk_id,
                    "metadata": doc.metadata,
                    "embedding": doc.embedding,
                }
                for doc in self.documents
            ]
        }
        Path(path).parent.mkdir(parents=True, exist_ok=True)
        with open(path, "w") as f:
            json.dump(data, f)

    def load(self, path: str):
        """Load vector store from disk."""
        with open(path, "r") as f:
            data = json.load(f)

        self.documents = []
        for item in data["documents"]:
            doc = Document(
                content=item["content"],
                source=item["source"],
                chunk_id=item["chunk_id"],
                metadata=item.get("metadata", {}),
                embedding=item.get("embedding"),
            )
            self.documents.append(doc)

        embeddings = [doc.embedding for doc in self.documents if doc.embedding is not None]
        if embeddings:
            self.embeddings = np.array(embeddings)


class DocumentLoader:
    """Loads and chunks documents from various sources."""

    def __init__(self, chunk_size: int = 1000, chunk_overlap: int = 200):
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap

    def load_text_file(self, file_path: str) -> str:
        """Load content from a text file."""
        with open(file_path, "r", encoding="utf-8") as f:
            return f.read()

    def load_directory(self, directory_path: str, extensions: List[str] = None) -> List[Dict]:
        """Load all supported files from a directory."""
        if extensions is None:
            extensions = [".txt", ".md", ".py", ".json", ".csv", ".html", ".rst"]

        raw_documents = []
        directory = Path(directory_path)

        if not directory.exists():
            print(f"Warning: Directory {directory_path} does not exist.")
            return raw_documents

        for ext in extensions:
            for file_path in directory.rglob(f"*{ext}"):
                try:
                    content = self.load_text_file(str(file_path))
                    raw_documents.append({
                        "content": content,
                        "source": str(file_path),
                        "metadata": {
                            "file_type": ext,
                            "file_name": file_path.name,
                            "file_size": file_path.stat().st_size,
                        },
                    })
                    print(f"  Loaded: {file_path.name}")
                except Exception as e:
                    print(f"  Error loading {file_path}: {e}")

        return raw_documents

    def chunk_text(self, text: str, source: str, metadata: Dict = None) -> List[Document]:
        """Split text into overlapping chunks."""
        if metadata is None:
            metadata = {}

        chunks = []
        if len(text) <= self.chunk_size:
            chunk_id = hashlib.md5(f"{source}:0".encode()).hexdigest()
            chunks.append(Document(
                content=text.strip(),
                source=source,
                chunk_id=chunk_id,
                metadata={**metadata, "chunk_index": 0, "total_chunks": 1},
            ))
            return chunks

        # Split by paragraphs first, then recombine into chunks
        paragraphs = text.split("\n\n")
        current_chunk = ""
        chunk_index = 0

        for paragraph in paragraphs:
            paragraph = paragraph.strip()
            if not paragraph:
                continue

            if len(current_chunk) + len(paragraph) + 2 <= self.chunk_size:
                current_chunk += ("\n\n" + paragraph if current_chunk else paragraph)
            else:
                if current_chunk:
                    chunk_id = hashlib.md5(f"{source}:{chunk_index}".encode()).hexdigest()
                    chunks.append(Document(
                        content=current_chunk.strip(),
                        source=source,
                        chunk_id=chunk_id,
                        metadata={**metadata, "chunk_index": chunk_index},
                    ))
                    chunk_index += 1

                    # Keep overlap from end of current chunk
                    overlap_text = current_chunk[-self.chunk_overlap:] if len(current_chunk) > self.chunk_overlap else ""
                    current_chunk = overlap_text + "\n\n" + paragraph if overlap_text else paragraph
                else:
                    # Paragraph itself is larger than chunk_size, split by sentences
                    sentences = self._split_into_sentences(paragraph)
                    for sentence in sentences:
                        if len(current_chunk) + len(sentence) + 1 <= self.chunk_size:
                            current_chunk += (" " + sentence if current_chunk else sentence)
                        else:
                            if current_chunk:
                                chunk_id = hashlib.md5(f"{source}:{chunk_index}".encode()).hexdigest()
                                chunks.append(Document(
                                    content=current_chunk.strip(),
                                    source=source,
                                    chunk_id=chunk_id,
                                    metadata={**metadata, "chunk_index": chunk_index},
                                ))
                                chunk_index += 1
                            current_chunk = sentence

        if current_chunk.strip():
            chunk_id = hashlib.md5(f"{source}:{chunk_index}".encode()).hexdigest()
            chunks.append(Document(
                content=current_chunk.strip(),
                source=source,
                chunk_id=chunk_id,
                metadata={**metadata, "chunk_index": chunk_index},
            ))

        # Update total_chunks in metadata
        for chunk in chunks:
            chunk.metadata["total_chunks"] = len(chunks)

        return chunks

    @staticmethod
    def _split_into_sentences(text: str) -> List[str]:
        """Simple sentence splitter."""
        import re
        sentences = re.split(r'(?<=[.!?])\s+', text)
        return [s.strip() for s in sentences if s.strip()]


class EmbeddingService:
    """Handles text embedding generation using OpenAI API."""

    def __init__(self, client: OpenAI, model: str = "text-embedding-3-small"):
        self.client = client
        self.model = model

    def embed_text(self, text: str) -> List[float]:
        """Generate embedding for a single text."""
        response = self.client.embeddings.create(
            input=text,
            model=self.model,
        )
        return response.data[0].embedding

    def embed_texts(self, texts: List[str], batch_size: int = 100) -> List[List[float]]:
        """Generate embeddings for multiple texts in batches."""
        all_embeddings = []
        for i in range(0, len(texts), batch_size):
            batch = texts[i:i + batch_size]
            response = self.client.embeddings.create(
                input=batch,
                model=self.model,
            )
            batch_embeddings = [item.embedding for item in response.data]
            all_embeddings.extend(batch_embeddings)
            print(f"  Embedded batch {i // batch_size + 1}/{(len(texts) - 1) // batch_size + 1}")
        return all_embeddings

    def embed_documents(self, documents: List[Document]) -> List[Document]:
        """Add embeddings to document objects."""
        texts = [doc.content for doc in documents]
        embeddings = self.embed_texts(texts)
        for doc, embedding in zip(documents, embeddings):
            doc.embedding = embedding
        return documents


class RAGSystem:
    """Main RAG system that orchestrates document loading, retrieval, and generation."""

    SYSTEM_PROMPT = """You are a helpful internal knowledge base assistant for our company. 
Your role is to answer questions based on the provided context from our company documents.

Guidelines:
- Answer questions accurately based ONLY on the provided context
- If the context doesn't contain enough information to answer, say so clearly
- Cite the source documents when possible
- Be concise but thorough
- If you're unsure about something, indicate your uncertainty
- Do not make up information that isn't in the provided context"""

    def __init__(
        self,
        openai_api_key: Optional[str] = None,
        embedding_model: str = "text-embedding-3-small",
        chat_model: str = "gpt-4o-mini",
        chunk_size: int = 1000,
        chunk_overlap: int = 200,
        top_k: int = 5,
    ):
        api_key = openai_api_key or os.getenv("OPENAI_API_KEY")
        if not api_key:
            raise ValueError(
                "OpenAI API key is required. Set OPENAI_API_KEY environment variable "
                "or pass openai_api_key parameter."
            )

        self.client = OpenAI(api_key=api_key)
        self.embedding_service = EmbeddingService(self.client, model=embedding_model)
        self.vector_store = VectorStore()
        self.document_loader = DocumentLoader(chunk_size=chunk_size, chunk_overlap=chunk_overlap)
        self.chat_model = chat_model
        self.top_k = top_k
        self.conversation_history: List[Dict[str, str]] = []

    def load_documents_from_directory(self, directory_path: str, extensions: List[str] = None):
        """Load, chunk, embed, and store documents from a directory."""
        print(f"\n📂 Loading documents from: {directory_path}")
        raw_docs = self.document_loader.load_directory(directory_path, extensions)

        if not raw_docs:
            print("No documents found.")
            return

        print(f"\n✂️  Chunking {len(raw_docs)} documents...")
        all_chunks = []
        for raw_doc in raw_docs:
            chunks = self.document_loader.chunk_text(
                text=raw_doc["content"],
                source=raw_doc["source"],
                metadata=raw_doc["metadata"],
            )
            all_chunks.extend(chunks)
        print(f"  Created {len(all_chunks)} chunks")

        print(f"\n🔢 Generating embeddings...")
        embedded_chunks = self.embedding_service.embed_documents(all_chunks)

        print(f"\n💾 Storing in vector database...")
        self.vector_store.add_documents(embedded_chunks)

        stats = self.vector_store.get_stats()
        print(f"\n✅ Knowledge base ready!")
        print(f"  Total chunks: {stats['total_documents']}")
        print(f"  Sources: {len(stats['sources'])} files")

    def load_text(self, text: str, source: str = "manual_input", metadata: Dict = None):
        """Load a single text string into the knowledge base."""
        if metadata is None:
            metadata = {}

        chunks = self.document_loader.chunk_text(text, source, metadata)
        embedded_chunks = self.embedding_service.embed_documents(chunks)
        self.vector_store.add_documents(embedded_chunks)
        print(f"Added {len(chunks)} chunks from: {source}")

    def load_texts(self, texts: List[Dict[str, str]]):
        """Load multiple text entries. Each dict should have 'content' and 'source' keys."""
        all_chunks = []
        for item in texts:
            chunks = self.document_loader.chunk_text(
                text=item["content"],
                source=item.get("source", "unknown"),
                metadata=item.get("metadata", {}),
            )
            all_chunks.extend(chunks)

        print(f"Embedding {len(all_chunks)} chunks...")
        embedded_chunks = self.embedding_service.embed_documents(all_chunks)
        self.vector_store.add_documents(embedded_chunks)
        print(f"Added {len(all_chunks)} chunks from {len(texts)} documents")

    def retrieve(self, query: str, top_k: Optional[int] = None) -> List[tuple]:
        """Retrieve relevant documents for a query."""
        k = top_k or self.top_k
        query_embedding = self.embedding_service.embed_text(query)
        results = self.vector_store.search(query_embedding, top_k=k)
        return results

    def _build_context(self, retrieved_docs: List[tuple]) -> str:
        """Build context string from retrieved documents."""
        context_parts = []
        for i, (doc, score) in enumerate(retrieved_docs, 1):
            context_parts.append(
                f"--- Document {i} (Source: {doc.source}, Relevance: {score:.3f}) ---\n"
                f"{doc.content}\n"
            )
        return "\n".join(context_parts)

    def _build_prompt(self, query: str, context: str) -> str:
        """Build the final prompt with context and query."""
        return (
            f"Based on the following context from our company documents, "
            f"please answer the user's question.\n\n"
            f"=== RETRIEVED CONTEXT ===\n{context}\n"
            f"=== END CONTEXT ===\n\n"
            f"User Question: {query}\n\n"
            f"Please provide a comprehensive answer based on the context above. "
            f"If the context doesn't fully address the question, mention what information is missing."
        )

    def query(
        self,
        user_query: str,
        top_k: Optional[int] = None,
        include_sources: bool = True,
        use_conversation_history: bool = True,
    ) -> Dict:
        """Process a user query through the full RAG pipeline."""
        # Step 1: Retrieve relevant documents
        retrieved_docs = self.retrieve(user_query, top_k)

        if not retrieved_docs:
            return {
                "answer": "I don't have any documents in my knowledge base yet. "
                          "Please load some documents first.",
                "sources": [],
                "context_used": "",
                "num_documents_retrieved": 0,
            }

        # Step 2: Build context from all retrieved documents
        context = self._build_context(retrieved_docs)

        # Step 3: Build the augmented prompt
        augmented_prompt = self._build_prompt(user_query, context)

        # Step 4: Build messages for the LLM
        messages = [{"role": "system", "content": self.SYSTEM_PROMPT}]

        if use_conversation_history and self.conversation_history:
            # Include recent conversation history (last 6 exchanges)
            recent_history = self.conversation_history[-12:]
            messages.extend(recent_history)

        messages.append({"role": "user", "content": augmented_prompt})

        # Step 5: Generate response using LLM
        response = self.client.chat.completions.create(
            model=self.chat_model,
            messages=messages,
            temperature=0.3,
            max_tokens=2000,
        )

        answer = response.choices[0].message.content

        # Step 6: Update conversation history
        self.conversation_history.append({"role": "user", "content": user_query})
        self.conversation_history.append({"role": "assistant", "content": answer})

        # Step 7: Compile sources
        sources = []
        if include_sources:
            for doc, score in retrieved_docs:
                sources.append({
                    "source": doc.source,
                    "chunk_id": doc.chunk_id,
                    "relevance_score": round(score, 4),
                    "content_preview": doc.content[:200] + "..." if len(doc.content) > 200 else doc.content,
                    "metadata": doc.metadata,
                })

        return {
            "answer": answer,
            "sources": sources,
            "context_used": context,
            "num_documents_retrieved": len(retrieved_docs),
            "model_used": self.chat_model,
            "tokens_used": {
                "prompt_tokens": response.usage.prompt_tokens,
                "completion_tokens": response.usage.completion_tokens,
                "total_tokens": response.usage.total_tokens,
            },
        }

    def clear_conversation_history(self):
        """Clear the conversation history."""
        self.conversation_history = []
        print("Conversation history cleared.")

    def save_knowledge_base(self, path: str = "knowledge_base.json"):
        """Save the vector store to disk."""
        self.vector_store.save(path)
        print(f"Knowledge base saved to: {path}")

    def load_knowledge_base(self, path: str = "knowledge_base.json"):
        """Load the vector store from disk."""
        self.vector_store.load(path)
        stats = self.vector_store.get_stats()
        print(f"Knowledge base loaded: {stats['total_documents']} chunks from {len(stats['sources'])} sources")

    def get_stats(self) -> Dict:
        """Get system statistics."""
        store_stats = self.vector_store.get_stats()
        return {
            **store_stats,
            "chat_model": self.chat_model,
            "top_k": self.top_k,
            "conversation_history_length": len(self.conversation_history),
        }


