def interactive_chat(rag: RAGSystem):
    """Run an interactive chat session."""
    print("\n" + "=" * 60)
    print("🤖 Acme Corporation Knowledge Base Chatbot")
    print("=" * 60)
    print("Type your questions below. Commands:")
    print("  'quit' or 'exit' - End the session")
    print("  'clear' - Clear conversation history")
    print("  'stats' - Show system statistics")
    print("  'sources' - Toggle source display")
    print("=" * 60 + "\n")

    show_sources = True

    while True:
        try:
            user_input = input("\n👤 You: ").strip()
        except (KeyboardInterrupt, EOFError):
            print("\n\nGoodbye! 👋")
            break

        if not user_input:
            continue

        if user_input.lower() in ("quit", "exit"):
            print("\nGoodbye! 👋")
            break

        if user_input.lower() == "clear":
            rag.clear_conversation_history()
            continue

        if user_input.lower() == "stats":
            stats = rag.get_stats()
            print("\n📊 System Statistics:")
            for key, value in stats.items():
                print(f"  {key}: {value}")
            continue

        if user_input.lower() == "sources":
            show_sources = not show_sources
            print(f"\nSource display: {'ON' if show_sources else 'OFF'}")
            continue

        print("\n🔍 Searching knowledge base...")
        result = rag.query(user_input)

        print(f"\n🤖 Assistant: {result['answer']}")

        if show_sources and result["sources"]:
            print(f"\n📚 Sources ({result['num_documents_retrieved']} documents retrieved):")
            for i, source in enumerate(result["sources"], 1):
                print(f"  {i}. {source['source']} (relevance: {source['relevance_score']})")

        if result.get("tokens_used"):
            tokens = result["tokens_used"]
            print(f"\n💰 Tokens used: {tokens['total_tokens']} "
                  f"(prompt: {tokens['prompt_tokens']}, completion: {tokens['completion_tokens']})")


def main():
    """Main entry point demonstrating the RAG system."""
    print("🚀 Acme Corporation Internal Knowledge Base RAG System")
    print("=" * 60)

    # Step 1: Create sample documents
    print("\n📝 Step 1: Creating sample company documents...")
    docs_dir = create_sample_documents()

    # Step 2: Initialize the RAG system
    print("\n⚙️  Step 2: Initializing RAG system...")
    try:
        rag = RAGSystem(
            embedding_model="text-embedding-3-small",
            chat_model="gpt-4o-mini",
            chunk_size=800,
            chunk_overlap=150,
            top_k=5,
        )
    except ValueError as e:
        print(f"\n❌ Error: {e}")
        print("\nTo use this system, set your OpenAI API key:")
        print("  export OPENAI_API_KEY='your-api-key-here'")
        return

    # Step 3: Load documents into the knowledge base
    print("\n📥 Step 3: Loading documents into knowledge base...")
    rag.load_documents_from_directory(docs_dir)

    # Step 4: Save knowledge base for future use
    rag.save_knowledge_base("acme_knowledge_base.json")

    # Step 5: Demo queries
    print("\n" + "=" * 60)
    print("📋 Step 4: Running demo queries...")
    print("=" * 60)

    demo_queries = [
        "What is the company's PTO policy?",
        "How do I report a security incident?",
        "What are the pricing options for Acme Platform products?",
        "What are the code review requirements for the engineering team?",
    ]

    for query in demo_queries:
        print(f"\n{'─' * 60}")
        print(f"👤 Query: {query}")
        result = rag.query(query, use_conversation_history=False)
        print(f"\n🤖 Answer: {result['answer']}")
        print(f"\n📚 Sources used: {result['num_documents_retrieved']}")
        for source in result["sources"][:3]:
            print(f"   - {source['source']} (score: {source['relevance_score']})")

    # Step 6: Interactive chat
    print("\n" + "=" * 60)
    print("Ready for interactive chat!")
    rag.clear_conversation_history()
    interactive_chat(rag)


if __name__ == "__main__":
    main()